const MN={
es:['ENE','FEB','MAR','ABR','MAY','JUN','JUL','AGO','SEP','OCT','NOV','DIC'],
en:['JAN','FEB','MAR','APR','MAY','JUN','JUL','AUG','SEP','OCT','NOV','DEC'],
pt:['JAN','FEV','MAR','ABR','MAI','JUN','JUL','AGO','SET','OUT','NOV','DEZ']
};
let lang=localStorage.getItem('pulz-lang')||'es';
function setLang(l){
    if(!T[l])return;
    lang=l;
    localStorage.setItem('pulz-lang',l);
    document.documentElement.lang=l;
    document.querySelectorAll('.lang-btn').forEach(b=>b.classList.toggle('active',b.textContent===l.toUpperCase()));
    document.querySelectorAll('[data-i18n]').forEach(el=>{const k=el.dataset.i18n;if(T[l][k])el.textContent=T[l][k]});
    if(typeof activeCountry!=='undefined'&&activeCountry&&typeof buildCountryContent==='function')buildCountryContent(activeCountry);
    if(typeof buildDD==='function')buildDD();
    if(typeof updateAuthUI==='function')updateAuthUI();
}
// Apply saved language as soon as DOM is ready
if(lang!=='es'){
    document.documentElement.lang=lang;
    document.addEventListener('DOMContentLoaded',()=>{
        document.querySelectorAll('[data-i18n]').forEach(el=>{const k=el.dataset.i18n;if(T[lang][k])el.textContent=T[lang][k]});
        document.querySelectorAll('.lang-btn').forEach(b=>b.classList.toggle('active',b.textContent===lang.toUpperCase()));
    });
}
